    ["Hide on Right-Click"] = "Nascondi al clic destro",
    ["Hide on Utility Cooldowns"] = "Nascondi su Cooldown utilità",
    ["Hide the + / - zoom buttons on the minimap. You can still mouse-wheel to zoom."] = "Nascondi i pulsanti zoom + / - sulla minimappa. Puoi comunque usare la rotellina per zoomare.",
    ["Hide the 1px accent border drawn around globally skinned frames."] = "Nascondi il bordo accentato da 1px disegnato attorno ai frame con skin globale.",
    ["Hide the 1px border drawn around all globally skinned frames."] = "Nascondi il bordo da 1px disegnato attorno a tutti i frame con skin globale.",
    ["Hide the Atonement spell icon and show only the count number."] = "Nascondi l'icona dell'incantesimo Atonement e mostra solo il numero del conteggio.",
    ["Hide the Blizzard calendar button on the minimap."] = "Nascondi il pulsante calendario Blizzard sulla minimappa.",
    ["Hide the Blizzard clock/stopwatch button on the minimap."] = "Nascondi il pulsante orologio/cronometro Blizzard sulla minimappa.",
    ["Hide the Blizzard zone-text label above the minimap. Use the QUI zone label below for a replacement."] = "Nascondi l'etichetta testo zona Blizzard sopra la minimappa. Usa il testo zona QUI qui sotto come sostituto.",
    ["Hide the QUI minimap button. You can still open the options panel via /qui."] = "Nascondi il pulsante minimappa QUI. Puoi comunque aprire il pannello opzioni con /qui.",
    ["Hide the action tracker while you are out of combat. Useful if you only want it active during pulls."] = "Nascondi il tracker azioni mentre sei fuori combattimento. Utile se vuoi che sia attivo solo durante le pull.",
    ["Hide the backdrop fill behind the M+ timer panel entirely."] = "Nascondi completamente il riempimento sfondo dietro al pannello timer M+.",
    ["Hide the background fill on this skin entirely. Only takes effect when the override above is enabled."] = "Nascondi completamente il riempimento sfondo di questa skin. Ha effetto solo quando l'override sopra è abilitato.",
    ["Hide the bar text until you mouse over the frame. Keeps the tracker visually clean between pulls."] = "Nascondi il testo della barra finché non passi il mouse sul frame. Mantiene il tracker visivamente pulito tra una pull e l'altra.",
    ["Hide the bar when no prey hunt is active. Turn off to keep a placeholder bar visible at all times."] = "Nascondi la barra quando nessuna caccia alla preda è attiva. Disattiva per mantenere sempre visibile una barra segnaposto.",
    ["Hide the bar whenever you leave the zone the current prey belongs to."] = "Nascondi la barra ogni volta che lasci la zona a cui appartiene la preda corrente.",
    ["Hide the border drawn around each spell icon."] = "Nascondi il bordo disegnato attorno a ogni icona incantesimo.",
    ["Hide the border drawn around the skinned objective tracker."] = "Nascondi il bordo disegnato attorno al tracker obiettivi rivestito.",
    ["Hide the border drawn around the tracker container."] = "Nascondi il bordo disegnato attorno al contenitore tracker.",
    ["Hide the border on this skin entirely. Only takes effect when the override above is enabled."] = "Nascondi completamente il bordo su questa skin. Ha effetto solo quando l'override sopra è abilitato.",
    ["Hide the border outline entirely."] = "Nascondi completamente il contorno del bordo.",
    ["Hide the buff frame entirely, even when hovering its anchor area."] = "Nascondi completamente il riquadro buff, anche quando passi il mouse sulla sua area di ancoraggio.",
    ["Hide the clockwise cooldown swipe animation drawn over %1$s icons. Duration text still works if it is enabled below."] = "Nascondi lo swipe cooldown in senso orario disegnato sopra le icone %1$s. Il testo durata continua a funzionare se è abilitato sotto.",
    ["Hide the combat timer outside of boss encounters, M+ dungeons, and PvP matches. Off shows the timer on every pull."] = "Nascondi il timer combattimento fuori dagli incontri boss, dungeon M+ e partite PvP. Off mostra il timer a ogni pull.",
    ["Hide the compact raid frame manager widget that lets you pick built-in raid profiles."] = "Nascondi il widget gestore riquadri raid compatti che ti permette di scegliere i profili raid integrati.",
    ["Hide the cooldown swipe animation drawn over icons."] = "Nascondi l'animazione di swipe cooldown disegnata sopra le icone.",
    ["Hide the cooldown swipe animation that fills the icon as time expires."] = "Nascondi l'animazione di swipe cooldown che riempie l'icona mentre il tempo scorre.",
    ["Hide the counter while in the open world. Useful if you only need it for instanced content."] = "Nascondi il contatore mentre sei nel mondo aperto. Utile se ti serve solo per i contenuti istanziati.",
    ["Hide the crafting/work order notification icon on the minimap."] = "Nascondi l'icona notifica di crafting/ordine di lavoro sulla minimappa.",
    ["Hide the debuff frame entirely, even when hovering its anchor area."] = "Nascondi completamente il riquadro debuff, anche quando passi il mouse sulla sua area di ancoraggio.",
    ["Hide the decorative Blizzard artwork around this button while keeping the button itself visible."] = "Nascondi la grafica decorativa Blizzard attorno a questo pulsante mantenendo il pulsante visibile.",
    ["Hide the default Blizzard prey indicator so only the QUI tracker is shown."] = "Nascondi l'indicatore preda predefinito Blizzard così viene mostrato solo il tracker QUI.",
    ["Hide the display while in the open world. Useful if you only care about raid buffs inside instances."] = "Nascondi la visualizzazione mentre sei nel mondo aperto. Utile se ti interessano solo i buff raid nelle istanze.",
    ["Hide the drawer toggle button until you mouse over the minimap."] = "Nascondi il pulsante di toggle del drawer finché non passi il mouse sulla minimappa.",
    ["Hide the duration and spell-name text on every bar in this container."] = "Nascondi il testo durata e nome incantesimo su ogni barra in questo contenitore.",
    ["Hide the duration countdown text on every icon in this row. The swipe animation still plays."] = "Nascondi il testo del conto alla rovescia durata su ogni icona di questa riga. L'animazione swipe continua comunque.",
    ["Hide the entire bar while you are in combat."] = "Nascondi l'intera barra mentre sei in combattimento.",
    ["Hide the experience and reputation bars while you are in a pet battle."] = "Nascondi le barre esperienza e reputazione mentre sei in una battaglia tra pet.",
    ["Hide the experience and reputation bars while you are riding a vehicle."] = "Nascondi le barre esperienza e reputazione mentre sei su un veicolo.",
    ["Hide the experience bar shown along the bottom of the screen while leveling."] = "Nascondi la barra esperienza mostrata in basso allo schermo mentre sali di livello.",
    ["Hide the garrison / mission table / expedition report button on the minimap."] = "Nascondi il pulsante guarnigione / tavolo missioni / rapporto spedizione sulla minimappa.",
    ["Hide the health bar shown on player, NPC, and enemy tooltips."] = "Nascondi la barra salute mostrata nei tooltip di giocatore, NPC e nemici.",
    ["Hide the instance difficulty indicator on the minimap."] = "Nascondi l'indicatore di difficoltà istanza sulla minimappa.",
    ["Hide the label and show only the value for this slot."] = "Nascondi l'etichetta e mostra solo il valore per questo slot.",
    ["Hide the label and show only the value for this widget."] = "Nascondi l'etichetta e mostra solo il valore per questo widget.",
    ["Hide the label and show only the value."] = "Nascondi l'etichetta e mostra solo il valore.",
    ["Hide the label text under/beside the icon row for a more compact display."] = "Nascondi il testo etichetta sotto/accanto alla riga di icone per una visualizzazione più compatta.",
    ["Hide the mail notification icon on the minimap. Requires a UI reload to take effect."] = "Nascondi l'icona notifica posta sulla minimappa. Richiede un ricaricamento dell'interfaccia per avere effetto.",
    ["Hide the missing raid buffs display when you aren't in a party or raid."] = "Nascondi la visualizzazione dei buff raid mancanti quando non sei in un gruppo o raid.",
    ["Hide the native Blizzard minimap border artwork at the top of the minimap."] = "Nascondi la grafica del bordo nativo Blizzard della minimappa nella parte superiore della minimappa.",
    ["Hide the numeric countdown on this spell's icon/bar only, while leaving other spells in the container unchanged."] = "Nascondi solo il conto alla rovescia numerico sull'icona/barra di questo incantesimo, lasciando invariati gli altri incantesimi nel contenitore.",
    ["Hide the objective tracker while you are in a Battleground."] = "Nascondi il tracker obiettivi mentre sei in un campo di battaglia.",
    ["Hide the objective tracker while you are in a Follower dungeon."] = "Nascondi il tracker obiettivi mentre sei in un dungeon di seguaci.",
    ["Hide the objective tracker while you are in a Heroic difficulty dungeon."] = "Nascondi il tracker obiettivi mentre sei in un dungeon di difficoltà Eroica.",
    ["Hide the objective tracker while you are in a Mythic difficulty dungeon."] = "Nascondi il tracker obiettivi mentre sei in un dungeon di difficoltà Mitica.",
    ["Hide the objective tracker while you are in a Normal difficulty dungeon."] = "Nascondi il tracker obiettivi mentre sei in un dungeon di difficoltà Normale.",
    ["Hide the objective tracker while you are in an Arena match."] = "Nascondi il tracker obiettivi mentre sei in un match Arena.",
    ["Hide the objective tracker while you are inside a raid instance."] = "Nascondi il tracker obiettivi mentre sei dentro un'istanza raid.",
    ["Hide the objective tracker while you are running a Mythic+ keystone."] = "Nascondi il tracker obiettivi mentre stai eseguendo una chiave Mitica+.",
    ["Hide the player buff frame entirely, including while mousing over its anchor area."] = "Nascondi completamente il riquadro buff del giocatore, anche mentre passi il mouse sulla sua area di ancoraggio.",
    ["Hide the player debuff frame entirely, including while mousing over its anchor area."] = "Nascondi completamente il riquadro debuff del giocatore, anche mentre passi il mouse sulla sua area di ancoraggio.",
    ["Hide the prey tracker bar while you are inside dungeons, raids, and other instances."] = "Nascondi la barra del tracciatore della preda mentre sei dentro dungeon, raid e altre istanze.",
    ["Hide the quest and objective tracker everywhere, ignoring the per-instance toggles below."] = "Nascondi il tracker missioni e obiettivi ovunque, ignorando i toggle per istanza qui sotto.",
    ["Hide the reputation tracking bar shown above the main action bar."] = "Nascondi la barra di tracciamento reputazione mostrata sopra la barra azione principale.",
    ["Hide the reticle while you are holding right mouse button to turn the camera."] = "Nascondi il reticolo mentre tieni premuto il tasto destro del mouse per ruotare la telecamera.",
    ["Hide the small arrow button above the buff frame that collapses your buffs into a dropdown."] = "Nascondi la piccola freccia sopra il riquadro buff che comprime i tuoi buff in un menu a discesa.",
    ["Hide the spell icon next to each bar, showing just the bar and text."] = "Nascondi l'icona incantesimo accanto a ogni barra, mostrando solo la barra e il testo.",
    ["Hide the standalone player unit frame whenever you are in a group, since the raid frames already show you."] = "Nascondi il riquadro unità giocatore autonomo ogni volta che sei in gruppo, poiché i riquadri raid ti mostrano già.",
    ["Hide the talking head frame used by cinematic NPC dialogue."] = "Nascondi il riquadro testa parlante usato dal dialogo cinematografico degli NPC.",
    ["Hide the time remaining text while casting an empowered spell so the stage markers read more clearly."] = "Nascondi il testo tempo rimanente mentre lanci un incantesimo potenziato così i marcatori di stadio si leggono più chiaramente.",
    ["Hide the tracking/eye icon on the minimap."] = "Nascondi l'icona tracciamento/occhio sulla minimappa.",
    ["Hide this HUD element while actively skyriding on a dynamic flying mount."] = "Nascondi questo elemento HUD mentre esegui skyriding su una cavalcatura volante dinamica.",
    ["Hide this HUD element while flying on a traditional (non-dynamic) flying mount."] = "Nascondi questo elemento HUD mentre voli su una cavalcatura volante tradizionale (non dinamica).",
    ["Hide this HUD element while you are mounted, overriding any Show rules above."] = "Nascondi questo elemento HUD mentre sei montato, sovrascrivendo eventuali regole Mostra sopra.",
    ["Hide this HUD element while you are riding a vehicle, overriding any Show rules above."] = "Nascondi questo elemento HUD mentre sei su un veicolo, sovrascrivendo eventuali regole Mostra sopra.",
    ["Hide this addon button from both the minimap and the drawer. Useful for buttons you never click."] = "Nascondi questo pulsante addon sia dalla minimappa sia dal drawer. Utile per i pulsanti che non clicchi mai.",
    ["Hide this chat frame's button bar while you are in combat, then restore it after combat ends."] = "Nascondi la barra dei pulsanti di questo riquadro chat mentre sei in combattimento, poi ripristinala al termine del combattimento.",
    ["Hide this frame whenever its anchor target is hidden, so dependent frames disappear together with the thing they follow."] = "Nascondi questo frame ogni volta che il suo bersaglio di ancoraggio è nascosto, così i frame dipendenti scompaiono insieme a ciò che seguono.",
    ["Hide this spell entirely from the CDM viewer. Useful for spells tracked automatically by the spec ruleset that you don't personally care about."] = "Nascondi completamente questo incantesimo dal visualizzatore CDM. Utile per incantesimi tracciati automaticamente dal set regole della specializzazione che non ti interessano personalmente.",
    ["Hide this widget's inline icon and keep the text. Not applied to icon-only widgets (Micro Menu, Travel) — hiding their icon would blank them."] = "Nascondi l'icona in linea di questo widget e mantieni il testo. Non si applica ai widget solo-icona (Micro Menu, Travel) - nascondere la loro icona li lascerebbe vuoti.",
    ["Hide this widget's text and keep only its icon. Text-only widgets (FPS, Gold, …) become blank."] = "Nascondi il testo di questo widget e mantieni solo la sua icona. I widget di solo testo (FPS, Gold, …) diventano vuoti.",
    ["Hide this window without deleting it. The window keeps its layout and overrides and reappears when toggled back on."] = "Nascondi questa finestra senza eliminarla. La finestra mantiene il suo layout e le sue sovrascritture e ricompare quando la riattivi.",
    ["Hides Blizzard tutorial popups, micro-button glows, and collection toasts."] = "Nasconde i popup tutorial Blizzard, i bagliori dei micro-pulsanti e i toast della collezione.",
    ["High"] = "Alto",
    ["Highlight Color"] = "Colore evidenziazione",
