    ["Show button bar for this frame"] = "Mostra la barra pulsanti per questo frame",
    ["Show colored gem dots indicating how many gem slots the item has and whether each is filled."] = "Mostra punti gemma colorati che indicano quanti slot gemma ha l'oggetto e se sono pieni.",
