    ["Use M+ timer-specific background settings instead of the shared skinning background. Enables the controls below."] = "Usa impostazioni sfondo specifiche per il timer M+ invece dello sfondo condiviso di skinning. Abilita i controlli sotto.",
    ["Use Power Type Color"] = "Usa colore tipo potere",
    ["Use QUI's colored timestamp prefix on new chat messages. While enabled, Blizzard's native chat timestamp is suppressed so the two do not stack."] = "Usa il prefisso timestamp colorato di QUI sui nuovi messaggi chat. Quando è attivo, il timestamp nativo di Blizzard viene soppresso così i due non si sovrappongono.",
    ["Use Time-Based Duration Color"] = "Usa colore durata basato sul tempo",
    ["Use a background color specific to this skin instead of the global default chosen in Theme & Colors."] = "Usa un colore di sfondo specifico per questa skin invece del predefinito globale scelto in Tema e colori.",
    ["Use a border style specific to this skin instead of the global default chosen in Theme & Colors."] = "Usa uno stile bordo specifico per questa skin invece del predefinito globale scelto in Tema e colori.",
    ["Use a custom color for the bar background instead of the default subtle fill."] = "Usa un colore di sfondo personalizzato per la barra invece del riempimento sottile predefinito.",
    ["Use a custom font for the combat text instead of inheriting the global QUI default font."] = "Usa un font personalizzato per il testo di combattimento invece di ereditare il font globale predefinito di QUI.",
    ["Use a cyan border instead of the quality color on items that belong to a saved equipment set (live views)."] = "Usa un bordo ciano invece del colore qualità sugli oggetti che appartengono a un set equipaggiamento salvato (viste live).",
    ["Use a per-spell bar color for this aura-bar spell instead of the container's default bar color."] = "Usa un colore barra specifico per questo incantesimo della aura-bar invece del colore barra predefinito del contenitore.",
    ["Use abbreviated distance labels (e.g., Melee/Close/Far) instead of longer phrasing."] = "Usa etichette distanza abbreviate (es. Melee/Close/Far) invece di frasi più lunghe.",
    ["Use green/yellow/red time-based duration colors instead of the static text color."] = "Usa colori durata basati sul tempo verde/giallo/rosso invece del colore testo statico.",
    ["Use the Frame Positioning tab to fine-tune frame positions relative to each other."] = "Usa la scheda Posizionamento frame per regolare con precisione le posizioni relative dei frame.",
    ["Use the Nudge tool for fine-grained pixel adjustments to any anchored element."] = "Usa lo strumento Nudge per regolazioni pixel fini di qualsiasi elemento ancorato.",
    ["Use the QUI theme accent color for proc glows, or a custom color."] = "Usa il colore accento del tema QUI per i bagliori proc, o un colore personalizzato.",
    ["Use the compact label variant for this slot."] = "Usa la variante etichetta compatta per questo slot.",
    ["Use the compact label variant for this widget."] = "Usa la variante etichetta compatta per questo widget.",
    ["Use |cFFFFFF00/qui layout|r to position frames, then click |cFFFFFF00Save|r."] = "Usa |cFFFFFF00/qui layout|r per posizionare i frame, poi clicca |cFFFFFF00Salva|r.",
    ["Use |cFFFFFF00100% Icon Size|r on CDM Essential & Utility bars for best results."] = "Usa |cFFFFFF00100% Dimensione icona|r sulle barre CDM Essential e Utility per i migliori risultati.",
    ["Use |cff60A5FA/cdm|r to open the Blizzard Cooldown Settings panel for viewer layout."] = "Usa |cff60A5FA/cdm|r per aprire il pannello Blizzard Cooldown Settings per il layout viewer.",
    ["Use |cff60A5FA/kb|r to set up keybinds by hovering over action buttons and pressing a key."] = "Usa |cff60A5FA/kb|r per configurare i binding passando sui pulsanti azione e premendo un tasto.",
    ["Use |cff60A5FA/qui layout|r or the |cff60A5FAQUI Edit Mode|r button to move QUI-managed frames, then fine-tune anchors and nudges in |cff60A5FAFrame Positioning|r"] = "Usa |cff60A5FA/qui layout|r o il pulsante |cff60A5FAQUI Edit Mode|r per spostare i frame gestiti da QUI, poi rifinisci ancore e nudges in |cff60A5FAPosizionamento frame|r",
